mapper.select:
SELECT * FROM BT_LEARNING

ORDER BY BOARD_GROUP DESC, BOARD_SEQUENCE ASC
LIMIT #{pageStart}, #{perPageNum}

mapper.update:
UPDATE BT_LEARNING
SET BOARD_SEQUENCE = BOARD_SEQUENCE + 1
WHERE BOARD_GROUP = #{board_group}
AND BOARD_SEQUENCE > #{board_sequence}

UPDATE BT_LEARNING
SET BOARD_AVAILABLE = #{role}
WHERE IDX = #{idx}

UPDATE BT_LEARNING 
SET TITLE = #{title}, CONTENT = #{content}, ATTACHED_DATA = #{attached_data}, ATTACHED_DATA2 = #{attached_data2}, LECTURE = #{lecture}
WHERE IDX = #{idx}
